#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main() {
    // Seed the random number generator (usually done once)
    srand(time(NULL));

    int min = 1;
    int max = 100;
    // Generate random number in range [min, max]
    // rand() % N gives a number in range [0, N-1]
    int random_num = rand() % (max - min + 1) + min;

    printf("Random number (%d-%d): %d\n", min, max, random_num);
    return 0;
}

