#include <stdio.h>
#include <string.h>

// Function to reverse a string in-place
void reverseString(char *str) {
    if (str == NULL) return; // Handle null pointer
    int n = strlen(str);
    if (n <= 1) return; // Nothing to reverse for empty or single-char string

    char *start = str;
    char *end = str + n - 1; // Point to the last character
    char temp;

    // Swap characters from start and end, moving inwards
    while (start < end) {
        temp = *start;
        *start = *end;
        *end = temp;
        start++;
        end--;
    }
}

int main() {
    char myString[] = "Hello World";
    printf("Original: %s\n", myString);
    reverseString(myString);
    printf("Reversed: %s\n", myString);

    char single[] = "A";
    reverseString(single);
    printf("Single char reversed: %s\n", single);

    char empty[] = "";
    reverseString(empty);
    printf("Empty string reversed: %s\n", empty);

    return 0;
}

