#include <stdio.h>

// Function to print the first n Fibonacci numbers (iterative)
// Uses unsigned long long to handle larger numbers
void printFibonacci(int n) {
    if (n <= 0) {
        printf("Number of terms must be positive.\n");
        return;
    }

    unsigned long long t1 = 0, t2 = 1, nextTerm;

    printf("Fibonacci Sequence (first %d terms):\n", n);

    for (int i = 1; i <= n; ++i) {
        // Print the current term
        if (i == 1) {
            printf("%llu", t1);
        } else if (i == 2) {
            printf(", %llu", t2);
        } else {
            // Check for potential overflow before calculation (simple check)
            // This check isn't perfect but catches many cases.
            // A more robust solution might use arbitrary-precision libraries.
            if (t1 > (unsigned long long)-1 - t2) {
                 printf("\nOverflow detected! Cannot calculate further terms.\n");
                 break;
            }
            nextTerm = t1 + t2;
            printf(", %llu", nextTerm);
            t1 = t2;
            t2 = nextTerm;
        }
    }
    printf("\n");
}

int main() {
    printFibonacci(10); // Print first 10 terms
    printFibonacci(93); // Near the limit for unsigned long long
    // printFibonacci(94); // Likely overflows unsigned long long
    printFibonacci(0);  // Test edge case
    return 0;
}

