#include <stdio.h>

// Function to calculate factorial (iterative)
// Returns unsigned long long, returns 0 for negative input or overflow.
unsigned long long factorial(int n) {
    if (n < 0) {
        fprintf(stderr, "Factorial not defined for negative numbers.\n");
        return 0; // Indicate error/undefined
    }
    if (n == 0) {
        return 1; // 0! = 1
    }

    unsigned long long fact = 1;
    unsigned long long prev_fact;

    for (int i = 1; i <= n; ++i) {
        prev_fact = fact;
        // Check for potential overflow before multiplication
        // If fact > ULLONG_MAX / i, then fact * i will overflow
        if (fact > (unsigned long long)-1 / i) {
             fprintf(stderr, "Overflow detected calculating factorial for %d!\n", n);
             return 0; // Indicate overflow
        }
        fact *= i;
    }
    return fact;
}

int main() {
    int num;
    unsigned long long result;

    num = 5;
    result = factorial(num);
    if (result != 0 || num == 0) printf("Factorial of %d = %llu\n", num, result);

    num = 0;
    result = factorial(num);
    if (result != 0 || num == 0) printf("Factorial of %d = %llu\n", num, result);

    num = 20; // Within unsigned long long range
    result = factorial(num);
    if (result != 0 || num == 0) printf("Factorial of %d = %llu\n", num, result);

    num = 21; // Likely overflows unsigned long long
    result = factorial(num);
     // If result is 0 and num is not 0, an error occurred (negative or overflow)
    if (result != 0 || num == 0) printf("Factorial of %d = %llu\n", num, result);

    num = -5; // Negative input
    result = factorial(num);
    // Should print error from function, result will be 0

    return 0;
}

