#include <stdio.h>
#include <stdbool.h> // For bool type (requires C99 or later)
#include <math.h>    // For sqrt()

// Function to check if a number is prime
// Handles integers up to the limit of int type.
bool isPrime(int n) {
    if (n <= 1) return false; // 0, 1, and negative numbers are not prime
    if (n <= 3) return true;  // 2 and 3 are prime

    // Eliminate multiples of 2 and 3 early
    if (n % 2 == 0 || n % 3 == 0) return false;

    // Check factors from 5 upwards, stepping by 6 (optimisation)
    // We only need to check up to sqrt(n)
    int limit = (int)sqrt(n);
    for (int i = 5; i <= limit; i = i + 6) {
        if (n % i == 0 || n % (i + 2) == 0)
            return false;
    }

    return true; // If no divisors found, it's prime
}

int main() {
    int nums_to_check[] = {0, 1, 2, 3, 4, 17, 25, 29, 97, 100, -5};
    int count = sizeof(nums_to_check) / sizeof(nums_to_check[0]);

    for (int i = 0; i < count; ++i) {
         int num = nums_to_check[i];
         if (isPrime(num)) {
            printf("%d is a prime number.\n", num);
        } else {
            printf("%d is not a prime number.\n", num);
        }
    }

    return 0;
}

