#include <stdio.h>
#include <stdlib.h> // For exit()

#define MAX_LINE_LENGTH 256 // Define a reasonable max line length

int main() {
    FILE *filePointer;
    char lineBuffer[MAX_LINE_LENGTH];
    const char *filename = "example.txt"; // Specify the file to read

    // Try to open the file for reading ("r")
    filePointer = fopen(filename, "r");

    // Check if the file was opened successfully
    if (filePointer == NULL) {
        perror("Error opening file"); // Print system error message related to errno
        fprintf(stderr, "Could not open file: %s\n", filename);
        // exit(EXIT_FAILURE); // Exit if file cannot be opened
        return 1; // Indicate error
    }

    printf("Content of %s:\n-----\n", filename);

    // Read the file line by line using fgets
    // fgets is generally safer than gets as it prevents buffer overflows
    // It reads up to n-1 characters, or until newline, or until EOF.
    while (fgets(lineBuffer, sizeof(lineBuffer), filePointer) != NULL) {
        // Print the line read from the file
        // fgets includes the newline character if it fits in the buffer
        printf("%s", lineBuffer);
    }

    // Check if the loop terminated due to an error
    if (ferror(filePointer)) {
        perror("Error reading file");
        fclose(filePointer); // Close file even on error
        return 1; // Indicate error
    }

    printf("-----\nEnd of file read.\n");

    // Close the file
    if (fclose(filePointer) != 0) {
         perror("Error closing file");
         return 1; // Indicate error
    }


    return 0; // Indicate success
}

