#include <stdio.h>
#include <stdlib.h> // For exit()

int main() {
    FILE *filePointer;
    const char *filename = "output.txt"; // Specify the file to write to
    const char *contentLine1 = "Hello from C! This is the first line.\n";
    const char *contentLine2 = "This is the second line written to the file.\n";

    // Try to open the file for writing ("w")
    // "w": Creates the file if it doesn't exist, TRUNCATES (empties) it if it does.
    // Use "a" to append instead of overwriting.
    filePointer = fopen(filename, "w");

    // Check if the file was opened successfully
    if (filePointer == NULL) {
        perror("Error opening file for writing");
        fprintf(stderr, "Could not open or create file: %s\n", filename);
        // exit(EXIT_FAILURE);
        return 1; // Indicate error
    }

    printf("Writing to file: %s\n", filename);

    // Write the content to the file using fputs or fprintf
    if (fputs(contentLine1, filePointer) == EOF) {
        perror("Error writing line 1 to file");
        fclose(filePointer); // Attempt to close file even on error
        return 1; // Indicate error
    }
    if (fprintf(filePointer, "%s", contentLine2) < 0) { // fprintf returns chars written or negative on error
         perror("Error writing line 2 to file");
         fclose(filePointer);
         return 1;
    }

    printf("Successfully wrote content.\n");

    // Close the file (this also flushes any buffered data)
     if (fclose(filePointer) != 0) {
         perror("Error closing file after writing");
         return 1; // Indicate error
    }

    printf("File closed successfully.\n");

    return 0; // Indicate success
}

