#include <stdio.h>
#include <time.h> // Required for time functions

int main() {
    time_t rawtime; // A type to hold calendar time (often integral type)
    struct tm *timeinfo; // A structure to hold broken-down time (year, month, day, hour, etc.)
    char buffer[80]; // Buffer to hold the formatted date/time string

    // 1. Get the current calendar time
    // time() returns the time as the number of seconds since the Epoch (00:00:00 UTC, Jan 1, 1970).
    // It can also store this value in the location pointed to by rawtime (if not NULL).
    time(&rawtime);
    // Alternatively: rawtime = time(NULL);

    // Check if time() failed (returns -1 on error, though rare on modern systems)
    if (rawtime == (time_t)(-1)) {
        perror("Error getting time");
        return 1;
    }

    // 2. Convert time_t to a struct tm representing LOCAL time
    // localtime() converts the calendar time to broken-down time expressed as local time.
    // Note: localtime returns a pointer to a static internal buffer, which might be overwritten
    // by subsequent calls to other time functions (like gmtime, ctime). Not thread-safe.
    // Use localtime_s or localtime_r for safer alternatives if available and needed.
    timeinfo = localtime(&rawtime);

    // Check if localtime() failed (returns NULL on error)
     if (timeinfo == NULL) {
        perror("Error converting to local time");
        return 1;
    }


    // 3. Format the time into a readable string using strftime()
    // strftime formats the broken-down time in timeinfo according to format specifiers.
    // Example format: "YYYY-MM-DD HH:MM:SS"
    // %Y: Year with century, %m: Month (01-12), %d: Day of month (01-31)
    // %H: Hour (00-23), %M: Minute (00-59), %S: Second (00-60, allows for leap seconds)
    strftime(buffer, sizeof(buffer), "%Y-%m-%d %H:%M:%S", timeinfo);
    printf("Current local time (YYYY-MM-DD HH:MM:SS): %s\n", buffer);

    // Example of another format: "Day, Month Date, Year, hh:mm:ss AM/PM Zone"
    // %A: Full weekday name, %B: Full month name, %d: Day of month
    // %Y: Year, %I: Hour (01-12), %M: Minute, %S: Second, %p: AM/PM
    // %Z: Time zone name (if available)
    strftime(buffer, sizeof(buffer), "%A, %B %d, %Y, %I:%M:%S %p %Z", timeinfo);
    printf("Formatted local time: %s\n", buffer);

    // 4. Print epoch time (seconds since Jan 1, 1970 UTC)
    // Note: printf needs %ld or similar for time_t, as its exact type can vary.
    // Using long for common compatibility, but check your system's time_t definition.
    printf("Seconds since epoch (UTC): %ld\n", (long)rawtime);

    // 5. Using asctime() for a standard string format (includes newline)
    // asctime converts a struct tm *directly* to a standard format string:
    // "Www Mmm dd hh:mm:ss yyyy\n"
    // Like localtime, it uses a static buffer. Not thread-safe.
    // printf("Standard format (asctime): %s", asctime(timeinfo)); // Already includes newline

    // 6. Using ctime() for a standard string format directly from time_t
    // ctime is equivalent to asctime(localtime(&rawtime)). Also uses static buffer.
    // printf("Standard format (ctime): %s", ctime(&rawtime)); // Already includes newline


    return 0;
}

