#include <stdio.h>
#include <limits.h> // For INT_MIN (minimum value for int)
#include <stdbool.h> // For bool

// Function to find the maximum value in an integer array
// Returns true and sets maxVal if successful, false if array is empty/null.
bool findMax(const int arr[], int size, int *maxVal) {
    if (arr == NULL || size <= 0) {
        fprintf(stderr, "Error: Array is null or empty.\n");
        // Optionally set maxVal to a specific error value, like INT_MIN
        if(maxVal != NULL) *maxVal = INT_MIN;
        return false; // Indicate failure
    }

    // Check if maxVal pointer is valid before dereferencing
    if (maxVal == NULL) {
        fprintf(stderr, "Error: Output pointer maxVal is NULL.\n");
        return false;
    }

    *maxVal = arr[0]; // Assume first element is the maximum initially

    // Iterate through the rest of the array
    for (int i = 1; i < size; i++) {
        if (arr[i] > *maxVal) {
            *maxVal = arr[i]; // Found a new maximum
        }
    }

    return true; // Indicate success
}

int main() {
    int numbers[] = {10, 5, 42, 17, 8, 99, 32, -5, 0};
    int size = sizeof(numbers) / sizeof(numbers[0]); // Calculate array size dynamically

    int maximumValue;

    printf("The array is: ");
    for(int i=0; i<size; i++) { printf("%d ", numbers[i]); }
    printf("\n");

    // Call the function to find the maximum
    if (findMax(numbers, size, &maximumValue)) {
        printf("Maximum value found: %d\n", maximumValue);
    } else {
        // Error message already printed by the function
        printf("Could not determine maximum value.\n");
    }

    // Test with empty array case
    printf("\nTesting with empty array:\n");
    int emptyArr[] = {};
    int emptySize = 0;
     if (findMax(emptyArr, emptySize, &maximumValue)) {
         printf("Maximum value found: %d (Should not happen for empty array)\n", maximumValue);
     } else {
         printf("Correctly handled empty array case.\n");
     }

     // Test with NULL array case
     printf("\nTesting with NULL array:\n");
      if (findMax(NULL, 5, &maximumValue)) {
         printf("Maximum value found: %d (Should not happen for NULL array)\n", maximumValue);
     } else {
         printf("Correctly handled NULL array case.\n");
     }

    return 0;
}
